import jibo = require('jibo');
import {CancelTokenSession} from 'jibo-cai-utils';

type EnrollmentResult = {
    timeout: boolean;
    noisy: boolean;
    loud: boolean;
    bad: boolean;
};
type CollectionCallback = (data: 'error'|EnrollmentResult) => void;

class VoiceEnroller {

    private timeout: number;//setTimeout index
    private timeoutTime: number = 6000;//timeout in ms
    private log: typeof jibo.log;
    private looperId: string;
    private loopId: string;
    private enroller: jibo.jetstream.request.EnrollmentTurnRequest;
    private onRecorded: CollectionCallback;
    private enrollmentSession:CancelTokenSession;

    constructor(log) {
        this.log = log;
    }

    init(looperId, loopId, timeout) {
        this.looperId = looperId;
        this.loopId = loopId;
        this.onRecorded = null;
        if (timeout !== undefined) {
            this.timeoutTime = timeout;
        }
    }

    _onEnrollmentStart() {
        this.log.info('enrollment started');
    }
    _onNeedMoreData(data) {
        this.log.info('NEED INPUT');
        if (this.timeout) {
            clearTimeout(this.timeout);
            this.timeout = null;
        }
        this.onRecorded(data);
    }

    //Ya gotta call this for each HJ we wanna record
    async startListen(attemptEnrollment:boolean, onRecorded:CollectionCallback) {
        this.onRecorded = onRecorded;
        const eSesh = this.enrollmentSession = new CancelTokenSession();
        try {
            this.enroller = await eSesh.wrap(jibo.jetstream.startEnrollmentTurn(this.looperId, 1));
        } catch (err) {
            this.log.error('starting enrollment turn failed', err);
            //TODO: Should we bail here with a different user facing message?
        }
        this.timeout = setTimeout(this.onTimeout.bind(this), this.timeoutTime);
        let result:EnrollmentResult = {
            timeout: false,
            loud: false,
            bad: false,
            noisy: false
        };
        jibo.jetstream.events.speakerEnrollment.once((data) => {
            if (!data.accepted) {
                /*
                From Rick:
                conditions are:
                POOR_QUALITY
                CLIPPING
                POOR_SNR
                NOT_SPEECH_LIKE
                NOT_CONSISTENT
                BAD_DURATION
                POOR_QUALITY is an OR of all the other conditions.
                BAD_DURATION is highly unlikely to be seen
                NOT_HEY_JIBO
                BAND_LIMITED
                POOR_QUALITY
                */
                // create a local result just for this error
                let result:EnrollmentResult = {
                    timeout: false,
                    loud: false,
                    bad: false,
                    noisy: false
                };
                data.problems.forEach((problem) => {
                    switch(problem) {
                        case 'CLIPPING':
                            result.loud = true;
                            break;
                        case 'POOR_SNR':
                            result.noisy = true;
                            break;
                        case 'NOT_SPEECH_LIKE':
                        case 'NOT_CONSISTENT':
                        case 'BAD_DURATION':
                        case 'NOT_HEY_JIBO':
                        case 'BAND_LIMITED':
                        case 'POOR_QUALITY':
                            result.bad = true;
                            break;
                    }
                });
                //if somehow there were no problems listed (that we recognized), then
                //just call it bad because it was still rejected
                if (!result.loud && !result.noisy && !result.bad) {
                    result.bad = true;
                }
                // Due to the way Jetstream handles this, it will try to listen until it gets a good
                // result, but currently we want to give the user feedback, so we'll cancel the turn
                // instead
                this.onFailure(result);
            }
        });
        //wait for turn to complete
        const turnResult = await eSesh.wrap(this.enroller.promise);
        if (this.timeout) {
            clearTimeout(this.timeout);
            this.timeout = null;
        }
        if (turnResult.status === 'FAILED') {
            this.log.error('enrollment turn failed', turnResult.message);
        } else if (attemptEnrollment) {
            try {
                //createSpeakerModel() will remove the previous speaker model, because we did
                //not tell it to append
                await eSesh.wrap(jibo.jetstream.createSpeakerModel(this.looperId));
                //if the speaker model could not be created, then createSpeakerModel will reject
                this.log.info('Looper successfully enrolled voice recognition');
                jibo.kb.loop.setEnrollmentVoice(this.looperId, true, (err) => {
                    if (err) {
                        this.log.warn('failed to set enrollment status ', err);
                    }
                });
            } catch (err) {
                this.log.error('creating speaker model failed', err);
                //TODO: Should we have a different user facing error message here?
                result.bad = true;
            }
        }
        this.onRecorded(result);
    }

    onTimeout() {
        this.log.info('enroller timed-out');
        this.timeout = null;
        this.enrollmentSession.cancel();
        let result:EnrollmentResult = {
            timeout: true,
            loud: false,
            bad: false,
            noisy: false
        };
        this.enroller.cancel().catch(() => false).then((canceled) => {
            if (!canceled) {
                this.log.info('unable to cancel enroller after timeout');
            }
            this.onRecorded(result);
        });
    }
    
    onFailure(result:EnrollmentResult) {
        this.log.info('enroller failed due to bad result');
        clearTimeout(this.timeout);
        this.timeout = null;
        this.enrollmentSession.cancel();
        this.enroller.cancel().catch(() => false).then((canceled) => {
            if (!canceled) {
                this.log.info('unable to cancel enroller after failure');
            }
            this.onRecorded(result);
        });
    }

    cleanup() {
        if (this.looperId) {
            jibo.jetstream.removePendingSamples(this.looperId)
            .catch((err) => {
                this.log.warn('Unable to remove pending enrollment samples on cleanup', err);
            });
        }
        this.looperId = null;
        if (this.enroller) {
            if (this.timeout) {
                clearTimeout(this.timeout);
                this.timeout = null;
                this.enroller.cancel();
            }
            this.enroller = null;
        }
        jibo.jetstream.events.speakerEnrollment.removeAllListeners();
        if (this.enrollmentSession) {
            this.enrollmentSession.cancel();
            this.enrollmentSession = null;
        }
        this.onRecorded = null;
    }

    destroy() {
        this.cleanup();
        this.log = null;
    }
}
export default VoiceEnroller;
