/// <reference path="../typings/index.d.ts" />
import {BeSkill, Options} from '@be/be-framework';
import jibo = require('jibo');
import VoiceEnroller from './enrollment/VoiceEnroller';
import FaceEnroller from './enrollment/FaceEnroller';
import NameEnroller from'./enrollment/NameEnroller';

class Introductions extends BeSkill {

    public flow: jibo.flow.FlowExecutor;

    private root: jibo.kb.Node;
    private voiceEnroller: VoiceEnroller;
    private faceEnroller: FaceEnroller;
    private nameEnroller: NameEnroller;

    private _blackboard: any;

    /**
     * Introductions skill constructor
     * @constructor
     * @param {String} [assetPack=''] The asset pack if loading from Be
     */
    constructor(assetPack?: Options) {
        super(assetPack);
        this.setEnrollmentLightRingOn = this.setEnrollmentLightRingOn.bind(this);
        this.setEnrollmentLightRingOff = this.setEnrollmentLightRingOff.bind(this);
    }

    preload(done: (err?: any) => void): void {
        done();
    }

    postInit(done) {
        jibo.kb.createModel('/introductions').loadRoot((err, root) => {
            if (err) {
                this.log.error('error loading introductions root from KB', err);
            }
            this.root = root;
            done();
        });
    }

    /**
     * Start the skill
     * @method open
     */
    open(result: any, refresh: Boolean, previousSkillName: string): void {
        if (refresh) {
            this.close(this.open.bind(this, result));
            return;
        }
        if (!result) {
            this.log.warn('no launch result. NBD if standalone');
            result = {
                nlu: {}
            };
        }
        let source;
        switch (previousSkillName) {
            case '@be/main-menu':
                source = 'menu';
                break;
            case '@be/who-am-i':
                source = 'who_am_i';
                break;
            case '@be/tutorial':
                source = 'fc';
                break;
            default:
                source = 'hey_jibo';
                break;
        }
        this.track('Introductions Opened', { launch_source: source });

        const entities = result && result.nlu && result.nlu.entities;
        let loopah = entities && entities.loopMemberReferent && entities.loopMemberReferent !== 'null' ? entities.loopMemberReferent.split(',')[0] : null;
        let enrollmentType = entities.enrollmentType;

        let enrolledBefore = false;
        if (!this.root.data.enrollmentRun) {
            this.root.data.enrollmentRun = true;
            this.root.save();
        }
        else {
            enrolledBefore = true;
        }

        this.voiceEnroller = new VoiceEnroller(this.log.createChild('VoiceEnroller'));
        this.faceEnroller = new FaceEnroller(this.log.createChild('FaceEnroller'));
        this.nameEnroller = new NameEnroller(this.log.createChild('NameEnroller'));

        // make the enrollments light up the sky like whoa-oh
        //TODO: Reimplement this in some way
        // jibo.gl.events.enrollmentListenStarted.on(this.setEnrollmentLightRingOn);
        // jibo.gl.events.enrollmentListenStopped.on(this.setEnrollmentLightRingOff);

        this._blackboard = {
            track:this.track,
            analyticsData: {
                voice_success: 0,
                voice_failure: 0,
                face_success: 0,
                face_failure: 0,
                name_success: 0,
                name_failure: 0,
                name_initial_success: false
            }
        };
        this.flow = jibo.flow.run(
            require('./flows/VoiceFaceTraining'), {
                params: {
                    looper: loopah,
                    voiceEnroller: this.voiceEnroller,
                    faceEnroller: this.faceEnroller,
                    nameEnroller: this.nameEnroller,
                    enrolledBefore: enrolledBefore,
                    embodiedListen: jibo.embodied.listen,
                    root: this.root,
                    enrollmentType: enrollmentType,
                    log: this.log.createChild('Enrollment')
                },
                enableLogging: true,
                assetPack: this.assetPack,
                blackboard: this._blackboard
            },
            (err, status) => {
                //let trainingResult = (this.flow as any).context.result;
                //if (trainingResult.transition == 'back') {//TODO: What to do?
                if (status !== jibo.bt.Status.INTERRUPTED) {
                    this.exit();
                }
            }
        );
    }

    /**
     * Stop and unload the skill
     * @method close
     */
    close(done: () => void): void {
        this.setEnrollmentLightRingOff();
        if (this.voiceEnroller) {
            this.voiceEnroller.destroy();
            this.voiceEnroller = null;
        }
        if (this.faceEnroller) {
            this.faceEnroller.destroy();
            this.faceEnroller = null;
        }
        if (this.nameEnroller) {
            this.nameEnroller.destroy();
            this.nameEnroller = null;
        }
        // jibo.gl.events.enrollmentListenStarted.removeListener(this.setEnrollmentLightRingOn);
        // jibo.gl.events.enrollmentListenStopped.removeListener(this.setEnrollmentLightRingOff);
        if (this._blackboard) {
            this.track('Introductions Finished', this._blackboard.analyticsData);
            if (this._blackboard.attentionHandler) {
                this._blackboard.attentionHandler.release();
                this._blackboard.attentionHandler = null;
            }
        }
        this._blackboard = null;
        //safety against interruptions:
        let reenableGL = () => {
            jibo.action.configure({orientToHJ: true});
            jibo.jetstream.resetHotwordMode().catch((err) => {
                this.log.error('GL RESUME FAILURE', err);
            }).then(() => {
                done();
            });
        };
        if (this.flow) {
            this.flow.stopAndDestroy().then(() => {
                this.flow = null;
                jibo.media.setViewfinder(false);//in case enrollment gets interrupted, hide the viewfinder
                if (jibo.face.views.currentView && jibo.face.views.currentView.id !== 'eyeView') {
                    jibo.face.views.changeView(
                        { removeAll: true, leaveEmpty: true },
                        () => { reenableGL(); },
                        () => { reenableGL(); }
                    );
                }
                else {
                    jibo.face.views.forceEyeView(() => {
                        reenableGL();
                    },
                    null, // onLoaded callback
                    null, // use default transitionOpen
                    null, // use default transitionClose
                    () => {
                        this.log.error('force eye view error, continuing anyway');
                        reenableGL();
                    });
                }
            });
        }
        else {
            reenableGL();
        }
    }

    private setEnrollmentLightRingOn() {
        jibo.embodied.listen.enterActiveMode(jibo.embodied.listen.ActiveListenMode.UI);
    }

    private setEnrollmentLightRingOff() {
        jibo.embodied.listen.exitActiveMode();
    }
}

module.exports = Introductions;
