import jibo = require('jibo');

class FaceEnroller {

    private log: typeof jibo.log;
    private looper: jibo.kb.UserNode;
    private trainingParams: {name:string, kind:'face'};


    constructor(log) {
        this.log = log;
    }

    init(_looper) {
        this.looper = _looper;
        this.trainingParams = {
            name: this.looper._id,
            kind: "face"
        };
    }

    cleanup() {
        this.looper = null;
        this.trainingParams = null;
    }

    destroy() {
        this.cleanup();
        this.log = null;
    }

    getLPSData() {
        // loop through current entities and collate motion and person entities
        // and return those values
        let data = jibo.lps.motionData;
        const len = data.entities.length;
        let _hasMovement = false;
        let _faceCount = 0;
        for (let i = 0; i < len; i++) {
            let itr = data.entities[i];

            // check for motion
            if (!_hasMovement && (itr.description === "motion")) {
                _hasMovement = true;
            }

            if (itr.description === "person") {
                _faceCount++;
            }
        }

        return {
            hasMovement: _hasMovement,
            faceCount: _faceCount
        };
    }

    createIdentity(cb) {
        jibo.ics.createIdentity(this.trainingParams, (error) => {
            cb(error);
        });
    }

    removeIdentity(cb) {
        jibo.ics.removeIdentity(this.trainingParams, (error) => {
            cb(error);
        });
    }

    trainFace(cb) {
        this._trainHelper((err) => {
            if (err && err === "detect-0") {
                // try again? unfortunately, we can get a 0-count when it seems like nothing has
                // changed and because that time is fairly short, it should be ok that we try again right away
                this._trainHelper(cb);
            }
            else {
                cb(err);
            }
        });
    }

    _trainHelper(cb) {
        jibo.ics.sendTrainingRequest(this.trainingParams, (error, data) => {
            if (!this.log) {
                return;
            }
            if (error) {
                this.log.warn('face training attempt failed. ', error, data);
                let errorType = "detect-many"; // default?
                if (data && data.detection) {
                    // bad orientation error
                    errorType = "detect-1";
                }
                else if (data && data.detections && data.detections.length <= 5) {
                    // error with specific detection count
                    errorType = "detect-" + data.detections.length;
                }
                cb(errorType);
            }
            else {
                this.log.info('face training attempt succeeded');
                cb(null);
            }
        });
    }

    initFaceEnrollment(cb) {
        // initialize the face enrollment flag to false if not set yet
        if (!this.looper.data.enrolled || (this.looper.data.enrolled.face === undefined)) {
            jibo.kb.loop.setEnrollmentFace(this.looper, false, (err) => {
                cb();
            });
        }
        else {
            cb();
        }
    }

    done(onDoneDone) {
        this.log.info('Looper successfully enrolled face recognition');
        jibo.kb.loop.setEnrollmentFace(this.looper, true, (err) => {
            if (err) {
                this.log.warn('failed to set enrollment status ', err);
            }
            onDoneDone();
        });
    }
}
export default FaceEnroller;
