import jibo = require('jibo');

class NameEnroller {

    public catastrophe: boolean = false;
    public pronunciationsGenerated: boolean = false;

    public log: typeof jibo.log;

    private looperName: string;
    private listener: jibo.jetstream.request.NameLearningRequest;
    private timeoutTime: number = 16000;
    private timeout: number;
    private callback: Function;
    private looperId: string;
    private initPromise: Promise<any>;

    constructor(log) {
        this.log = log;
    }

    init(looperName, looperId, modelExists) {
        this.looperId = looperId;
        this.looperName = looperName;
        //start initializing, don't need to wait right now
        this.initPromise = jibo.jetstream.initNameLearning(looperName).then(() => {
            this.pronunciationsGenerated = true;
        }).catch((err) => {
            this.catastrophe = true;
            throw err;
        });
    }

    async whoAreYou(callback, timeout:number) {
        this.callback = callback;
        this.timeoutTime = timeout || this.timeoutTime;

        try {
            await this.initPromise;//make sure we initialized
            this.listener = await jibo.jetstream.startNameLearningTurn(this.looperName);
            this.timeout = setTimeout(this._onTimeout.bind(this), this.timeoutTime);
            const result = await this.listener.promise;
            this._onSuccess(result.message);
        } catch (err) {
            //don't error if already timed out
            if (this.timeout) {
                this._onError(err);
            }
        }
    }

    _onTimeout() {
        this.log.info('pronunciation listen timed-out');
        this.listener.cancel();
        this._onError();
    }

    _onError(data?) {
        if (this.timeout) {
            clearTimeout(this.timeout);
            this.timeout = null;
        }
        this.log.info('pronunciation error');//, data);
        this.listener.events.removeAllListeners();
        this.callback();
    }

    _onSuccess(pronunciation: string) {
        if (this.timeout) {
            clearTimeout(this.timeout);
            this.timeout = null;
        }
        this.log.info('heard pronunciations');//, pronunciation);
        this.listener.events.removeAllListeners();
        this.callback(pronunciation);
    }

    cleanup() {
        if (this.timeout) {
            clearTimeout(this.timeout);
            this.timeout = null;
        }
        this.callback = null;
        this.pronunciationsGenerated = false;
        this.looperId = null;
        if (this.listener) {
            this.listener.events.removeAllListeners();
            this.listener.cancel();
        }
    }

    destroy() {
        this.cleanup();
        this.log = null;
    }
}
export default NameEnroller;
